/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER trg_enrolments_max_3_attempts
BEFORE INSERT ON enrolments
FOR EACH ROW
BEGIN
    DECLARE v_attempt_count INT;

    SELECT COUNT(*)
    INTO v_attempt_count
    FROM enrolments
    WHERE student_id = NEW.student_id
      AND course_code = NEW.course_code;

    IF v_attempt_count >= 3 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Maximum 3 attempts allowed for this course';
    END IF;
END */;;
DELIMITER ;
